#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char s[200005]; scanf("%s",s);
        char ans[200005]; int ans_sz=0;
        char stack[200005]; int stack_sz;
        for(int i=0;i<N;i++){
            char c=s[i];
            stack_sz=0;
            while(ans_sz>0 && ans[ans_sz-1]-c==1){
                stack[stack_sz++]=ans[--ans_sz];
            }
            ans[ans_sz++]=c;
            while(stack_sz>0){
                ans[ans_sz++]=stack[--stack_sz];
            }
        }
        ans[ans_sz]='\0';
        printf("%s\n",ans);
    }
    return 0;
}

